code.Java:
import java.io.*;
public class Main{
    public static void main(String[] args) throws Exception{
        BufferedReader br=new BufferedReader(new InputStreamReader(System.in));
        String line=br.readLine();
        if(line==null||line.isEmpty()) return;
        int T=Integer.parseInt(line.trim());
        StringBuilder sb=new StringBuilder();
        for(int t=0;t<T;t++){
            long ticketPrice=Long.parseLong(br.readLine().trim());
            long numTickets=Long.parseLong(br.readLine().trim());
            long expenses=Long.parseLong(br.readLine().trim());
            long snackEarnings=Long.parseLong(br.readLine().trim());
            long gross=ticketPrice*numTickets;
            long after=gross-expenses;
            long total=after+snackEarnings;
            sb.append("Gross Revenue from Tickets: ").append(gross).append('\n');
            sb.append("Revenue After Expenses: ").append(after).append('\n');
            sb.append("Final Total with Snacks: ").append(total).append('\n');
        }
        System.out.print(sb.toString());
    }
}

